import{_ as t}from"./chunks/rby-software-stack-white.BBLgN_mm.js";import{_ as o,c as a,a1 as r,o as i}from"./chunks/framework.Bff2UY46.js";const h=JSON.parse('{"title":"Software Stack","description":"","frontmatter":{"title":"Software Stack","outline":"deep"},"headers":[],"relativePath":"docs/introduction/sw/software-stack.md","filePath":"docs/introduction/sw/software-stack.md"}'),s={name:"docs/introduction/sw/software-stack.md"};function n(l,e,c,d,m,u){return i(),a("div",null,e[0]||(e[0]=[r('<h1 id="software-stack" tabindex="-1">Software Stack <a class="header-anchor" href="#software-stack" aria-label="Permalink to &quot;Software Stack&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The software architecture ensures stable performance and safety while providing scalability for the robot. It covers various needs and enables easy and fast application development with scalable software structures.</p><figure><img src="'+t+'" alt="missing" style="margin:auto;"><figcaption style="text-align:center;">[ Software stack of RB-Y1 ]</figcaption></figure><p>This software structure is composed as follows:</p><ul><li><strong>Independent robot internal controllers (Robot PC)</strong>: Ensures stable performance and safety. Dualized with an application control PC (<strong>User PC</strong>) for scalability.</li><li><strong>Non-realtime communication channels</strong>: Used for high-level commands and robot settings such as power control. Commands can be built using a builder pattern and sent to the robot for execution. Non-realtime communication uses gRPC and can support up to 100Hz.</li><li><strong>Realtime command channels</strong>: Dedicated for low-level commands that require real-time response. Realtime control is based on UDP and can support up to 500Hz using a custom controller.</li><li>A <strong>robot model library</strong>: Allows for the building of simulation environments and provides access to the robot&#39;s kinematic and dynamic parameters.</li><li>Various libraries for implementing higher-level control (e.g., motion/task planner).</li></ul><h2 id="simulation" tabindex="-1">Simulation <a class="header-anchor" href="#simulation" aria-label="Permalink to &quot;Simulation&quot;">​</a></h2><blockquote><p>🚧 Simulation models (URDF/MJCF) will be provided soon.</p></blockquote>',8)]))}const b=o(s,[["render",n]]);export{h as __pageData,b as default};
